/*
 * Embeds the bootstrap ZIP as binary data inside the native library.
 *
 * The .incbin directive includes the raw bytes of the ZIP file into
 * the .rodata (read-only data) section of the shared library.
 * This is the same technique used by Termux (termux-bootstrap-zip.S).
 *
 * The symbols 'blob' and 'blob_size' are accessed from the JNI bridge
 * (novaterm-bootstrap.c) to create a Java byte[] with the ZIP contents.
 *
 * To use: place bootstrap-aarch64.zip in this directory (app/src/main/cpp/)
 * and rebuild. The ZIP is generated by the bootstrap CI workflow.
 *
 * Only arm64-v8a is supported (NovaTerm targets modern flagships only).
 */

    .global blob
    .global blob_size

    .section .rodata

blob:
    .incbin "bootstrap-aarch64.zip"
1:

blob_size:
    .int 1b - blob
